import express from 'express';
import { WebSocketServer, WebSocket } from 'ws';
import { createServer } from 'http';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));

const app = express();
const httpServer = createServer(app);

app.use(express.static(path.join(__dirname, '../client')));
app.use(express.json());
import pool from './db.js';

const wss = new WebSocketServer({ server: httpServer });

const rooms = new Map(); // roomCode → { player1, player2, spectators: Set(), names: {} }

wss.on('connection', (ws) => {
    console.log('Новый клиент подключился');

    let currentRoom = null;
    ws.on('message', (data) => {
        try {
            const msg = JSON.parse(data.toString());
            console.log(`Message:`, msg);

            if (msg.type === 'createRoom') {
                const code = Math.random().toString(36).substring(2, 8).toUpperCase();
                rooms.set(code, {
                    player1: ws,
                    player2: null,
                    spectators: new Set(),
                    names: { player1: msg.name },
                    gameStates: { player1: null, player2: null }
                });
                ws.send(JSON.stringify({ type: 'roomCreated', code, role: 'player1' }));
                currentRoom = code;
                console.log(`Room ${code} created`);
            } else if (msg.type === 'joinRoom') {
                const room = rooms.get(msg.code);
                if (!room) return ws.send(JSON.stringify({ type: 'error', message: 'Комната не найдена' }));
                currentRoom = msg.code;

                if (msg.role === 'player2' && !room.player2) {
                    room.player2 = ws;
                    room.names.player2 = msg.name;
                    // Отправляем player1 сообщение о присоединении player2
                    if (room.player1 && room.player1.readyState === WebSocket.OPEN) {
                        room.player1.send(JSON.stringify({ type: 'playerJoined', code: msg.code, name: msg.name }));
                    }
                    // Отправляем player2 подтверждение присоединения
                    ws.send(JSON.stringify({ type: 'joined', role: 'player2', code: msg.code, opponent: room.names.player1 }));
                    console.log(`Player2 ${msg.name} присоединился к комнате ${msg.code}`);
                } else if (msg.role === 'spectator') {
                    room.spectators.add(ws);
                    ws.send(JSON.stringify({ 
                        type: 'joined', 
                        role: 'spectator', 
                        code: msg.code,
                        player1Name: room.names.player1 || 'Игрок 1',
                        player2Name: room.names.player2 || 'Игрок 2'
                    }));
                    console.log(`Зритель${msg.name ? ' ' + msg.name : ''} присоединился к комнате ${msg.code}`);
                }
            } else if (msg.type === 'move' && msg.code) {
                const room = rooms.get(msg.code);
                if (room) {
                    // Broadcast move/state to room
                    const senderRole = room.player1 === ws ? 'player1' : room.player2 === ws ? 'player2' : null;
                    const stateMsg = { type: 'gameState', state: msg.state || {}, senderRole: senderRole };
                    [room.player1, room.player2, ...room.spectators].forEach(client => {
                        if (client && client !== ws && client.readyState === WebSocket.OPEN) client.send(JSON.stringify(stateMsg));
                    });
                }
            } else if (msg.type === 'gameState' && msg.code) {
                const room = rooms.get(msg.code);
                if (room) {
                    console.log(` Received gameState from room ${msg.code}, broadcasting...`);
                    // Determine which player sent this state
                    const senderRole = room.player1 === ws ? 'player1' : room.player2 === ws ? 'player2' : null;
                    // Broadcast game state to all EXCEPT sender
                    const stateMsg = { type: 'gameState', state: msg.state, senderRole: senderRole };
                    [room.player1, room.player2, ...room.spectators].forEach(client => {
                        if (client && client !== ws && client.readyState === WebSocket.OPEN) {
                            client.send(JSON.stringify(stateMsg));
                        }
                    });
                }
            } else if (msg.type === 'ready' && msg.code) {
                const room = rooms.get(msg.code);
                if (room) {
                    const playerKey = room.player1 === ws ? 'player1' : 'player2';
                    room.ready = room.ready || {};
                    room.ready[playerKey] = msg.ready;

                    // Notify other player
                    const otherPlayer = room.player1 === ws ? room.player2 : room.player1;
                    if (otherPlayer && otherPlayer.readyState === WebSocket.OPEN) {
                        otherPlayer.send(JSON.stringify({
                            type: 'playerReady',
                            ready: msg.ready,
                            code: msg.code
                        }));
                    }

                    // Check if both ready
                    if (room.player2 && room.ready.player1 && room.ready.player2) {
                        // Countdown
                        let count = 3;
                        const countdownInterval = setInterval(() => {
                            [room.player1, room.player2, ...room.spectators].forEach(client => {
                                if (client.readyState === WebSocket.OPEN) {
                                    client.send(JSON.stringify({type: 'countdown', count, code: msg.code}));
                                }
                            });
                            count--;
                            if (count < 0) {
                                clearInterval(countdownInterval);
                                [room.player1, room.player2, ...room.spectators].forEach(client => {
                                    if (client.readyState === WebSocket.OPEN) {
                                        client.send(JSON.stringify({
                                            type: 'startGame', 
                                            code: msg.code,
                                            player1Name: room.names.player1 || 'Игрок 1',
                                            player2Name: room.names.player2 || 'Игрок 2'
                                        }));
                                    }
                                });
                            }
                        }, 1000);
                    }
                }
            } else if (msg.type === 'reaction' && msg.code) {
                const room = rooms.get(msg.code);
                if (room) {
                    const reactionMsg = { type: 'reaction', reaction: msg.reaction };
                    [room.player1, room.player2, ...room.spectators].forEach(client => {
                        if (client.readyState === WebSocket.OPEN && client !== ws) {
                            client.send(JSON.stringify(reactionMsg));
                        }
                    });
                }
            }
        } catch (e) {
            console.error('WS Error:', e);
        }
    });

    ws.on('close', () => {
        // Cleanup room if empty
        for (let [code, room] of rooms) {
            if (room.player1 === ws) {
                room.player1 = null;
                console.log(`Player1 вышел из комнаты ${code}`);
            }
            if (room.player2 === ws) {
                room.player2 = null;
                console.log(`Player2 вышел из комнаты ${code}`);
            }
            room.spectators.delete(ws);

            // Удаляем пустую комнату
            if (!room.player1 && !room.player2 && room.spectators.size === 0) {
                rooms.delete(code);
                console.log(`Комната ${code} удалена`);
            }
        }
    });


});

// API Routes
app.post('/api/scores', async (req, res) => {
  try {
    const { name, score } = req.body;
    await pool.query('INSERT INTO scores (name, score, created_at) VALUES ($1, $2, NOW())', [name, score]);
    res.json({success: true});
  } catch (e) {
    res.status(500).json({error: e.message});
  }
});

app.get('/api/top10', async (req, res) => {
  try {
    const result = await pool.query('SELECT name, score, created_at FROM scores ORDER BY score DESC LIMIT 10');
    res.json(result.rows);
  } catch (e) {
    res.json([]);
  }
});

// Запуск сервера
const PORT = process.env.PORT || 3000;
httpServer.listen(PORT, () => {
    console.log(` Сервер на http://localhost:${PORT}`);
    console.log(`WS: ws://localhost:${PORT}`);
});

import express from 'express';
import { WebSocketServer, WebSocket } from 'ws';
import { createServer } from 'http';
import path from 'path';
import { fileURLToPath } from 'url';
import dotenv from 'dotenv';

// Import services
import { PlayerService } from './services/PlayerService.js';
import { RoomService } from './services/RoomService.js';
import { MatchService } from './services/MatchService.js';
import { authenticateWS } from './middleware/authMiddleware.js';

// Import routes
import authRoutes from './routes/auth.js';
import playerRoutes from './routes/player.js';
import leaderboardRoutes from './routes/leaderboard.js';

import pool from './db.js';

dotenv.config();

const __dirname = path.dirname(fileURLToPath(import.meta.url));

const app = express();
const httpServer = createServer(app);

// Middleware
app.use(express.static(path.join(__dirname, '../client')));
app.use(express.json());

// Routes
app.use('/api/auth', authRoutes);
app.use('/api/player', playerRoutes);
app.use('/api/leaderboard', leaderboardRoutes);

// WebSocket server
const wss = new WebSocketServer({ server: httpServer });

// In-memory room management (transient game sessions)
const rooms = new Map(); // roomCode → { player1WS, player2WS, spectators: Set(), match: {matchId, ...}, ...}

wss.on('connection', (ws) => {
  console.log(' New WebSocket client connected');

  let currentRoom = null;
  let playerId = null;
  let role = null;

  ws.on('message', async (data) => {
    try {
      const msg = JSON.parse(data.toString());
      console.log(` Message:`, msg.type);

      // Authenticate first (except for connection handshake)
      if (msg.type !== 'ping') {
        const auth = authenticateWS(msg);
        if (!auth) {
          return ws.send(JSON.stringify({ type: 'error', message: 'Authentication failed' }));
        }
        playerId = auth.playerId;
      }

      if (msg.type === 'createRoom') {
        try {
          const room = await RoomService.createRoom(playerId);
          const roomCode = room.room_code;
          currentRoom = roomCode;
          role = 'player1';

          rooms.set(roomCode, {
            player1: { ws, playerId, name: msg.name },
            player2: null,
            spectators: new Set(),
            match: null
          });

          ws.send(JSON.stringify({ 
            type: 'roomCreated', 
            code: roomCode, 
            role: 'player1',
            message: `Room created. Share code: ${roomCode}`
          }));

          console.log(`✅ Room ${roomCode} created by player ${playerId}`);
        } catch (err) {
          ws.send(JSON.stringify({ type: 'error', message: err.message }));
        }

      } else if (msg.type === 'joinRoom') {
        try {
          const room = rooms.get(msg.code);
          if (!room) {
            return ws.send(JSON.stringify({ type: 'error', message: 'Room not found' }));
          }

          currentRoom = msg.code;
          role = msg.role;

          if (msg.role === 'player2' && !room.player2) {
            room.player2 = { ws, playerId, name: msg.name };

            // Notify player1
            if (room.player1.ws.readyState === WebSocket.OPEN) {
              room.player1.ws.send(JSON.stringify({
                type: 'playerJoined',
                role: 'player2',
                name: msg.name
              }));
            }

            // Confirm to player2
            ws.send(JSON.stringify({
              type: 'joined',
              role: 'player2',
              code: msg.code,
              opponent: room.player1.name
            }));

            console.log(`✅ Player2 joined room ${msg.code}`);

          } else if (msg.role === 'spectator') {
            room.spectators.add({ ws, playerId, name: msg.name });

            ws.send(JSON.stringify({
              type: 'joined',
              role: 'spectator',
              code: msg.code,
              player1Name: room.player1.name,
              player2Name: room.player2?.name || 'Waiting...'
            }));

            console.log(`️ Spectator joined room ${msg.code}`);
          } else {
            ws.send(JSON.stringify({ type: 'error', message: 'Invalid role or slot taken' }));
          }
        } catch (err) {
          ws.send(JSON.stringify({ type: 'error', message: err.message }));
        }

      } else if (msg.type === 'ready' && currentRoom) {
        const room = rooms.get(currentRoom);
        if (!room) return;

        if (role === 'player1') room.player1.ready = msg.ready;
        else if (role === 'player2') room.player2.ready = msg.ready;

        // Notify opponent
        const other = role === 'player1' ? room.player2 : room.player1;
        if (other?.ws?.readyState === WebSocket.OPEN) {
          other.ws.send(JSON.stringify({ type: 'playerReady', ready: msg.ready }));
        }

        // Start game if both ready
        if (room.player1?.ready && room.player2?.ready && !room.matchStarted) {
          room.matchStarted = true;

          // Create match in DB
          try {
            const match = await MatchService.createMatch(
              currentRoom,
              room.player1.playerId,
              room.player2.playerId
            );
            room.match = match;

            // 3-second countdown
            let count = 3;
            const countdownInterval = setInterval(() => {
              [room.player1.ws, room.player2.ws, ...Array.from(room.spectators).map(s => s.ws)].forEach(client => {
                if (client?.readyState === WebSocket.OPEN) {
                  client.send(JSON.stringify({ type: 'countdown', count }));
                }
              });
              count--;
              if (count < 0) {
                clearInterval(countdownInterval);
                [room.player1.ws, room.player2.ws, ...Array.from(room.spectators).map(s => s.ws)].forEach(client => {
                  if (client?.readyState === WebSocket.OPEN) {
                    client.send(JSON.stringify({
                      type: 'startGame',
                      code: currentRoom,
                      player1Name: room.player1.name,
                      player2Name: room.player2.name
                    }));
                  }
                });
              }
            }, 1000);
          } catch (err) {
            console.error('Failed to create match:', err);
          }
        }

      } else if (msg.type === 'gameState' && currentRoom) {
        const room = rooms.get(currentRoom);
        if (!room) return;

        const stateMsg = { 
          type: 'gameState', 
          state: msg.state, 
          senderRole: role 
        };

        [room.player1.ws, room.player2.ws, ...Array.from(room.spectators).map(s => s.ws)].forEach(client => {
          if (client !== ws && client?.readyState === WebSocket.OPEN) {
            client.send(JSON.stringify(stateMsg));
          }
        });

      } else if (msg.type === 'gameEnd' && currentRoom) {
        const room = rooms.get(currentRoom);
        if (!room || !room.match) return;

        try {
          const p1Score = msg.player1Score || 0;
          const p2Score = msg.player2Score || 0;
          const durationSeconds = msg.duration || 0;

          await MatchService.updateMatchResult(
            room.match.match_id,
            p1Score,
            p2Score,
            msg.player1Lines || 0,
            msg.player2Lines || 0,
            durationSeconds
          );

          // Notify all clients
          [room.player1.ws, room.player2.ws, ...Array.from(room.spectators).map(s => s.ws)].forEach(client => {
            if (client?.readyState === WebSocket.OPEN) {
              client.send(JSON.stringify({
                type: 'matchEnded',
                winner: p1Score > p2Score ? 'player1' : 'player2',
                player1Score: p1Score,
                player2Score: p2Score
              }));
            }
          });

          console.log(` Match ${room.match.match_id} ended`);
        } catch (err) {
          console.error('Failed to end match:', err);
        }

      } else if (msg.type === 'reaction' && currentRoom) {
        const room = rooms.get(currentRoom);
        if (!room) return;

        [room.player1.ws, room.player2.ws, ...Array.from(room.spectators).map(s => s.ws)].forEach(client => {
          if (client !== ws && client?.readyState === WebSocket.OPEN) {
            client.send(JSON.stringify({
              type: 'reaction',
              reaction: msg.reaction,
              from: msg.name
            }));
          }
        });

      } else if (msg.type === 'ping') {
        ws.send(JSON.stringify({ type: 'pong' }));
      }

    } catch (err) {
      console.error('❌ WS Error:', err);
      ws.send(JSON.stringify({ type: 'error', message: 'Server error' }));
    }
  });

  ws.on('close', async () => {
    console.log(' Client disconnected');

    if (currentRoom && playerId) {
      try {
        const room = rooms.get(currentRoom);
        if (!room) return;

        // Remove player from room
        if (room.player1?.playerId === playerId) {
          room.player1 = null;
        } else if (room.player2?.playerId === playerId) {
          room.player2 = null;
        } else {
          room.spectators.forEach(s => {
            if (s.playerId === playerId) {
              room.spectators.delete(s);
            }
          });
        }

        // End room if empty
        if (!room.player1 && !room.player2 && room.spectators.size === 0) {
          try {
            await RoomService.endRoom(currentRoom);
          } catch (err) {
            console.error('Failed to end room:', err);
          }
          rooms.delete(currentRoom);
          console.log(`️ Room ${currentRoom} deleted`);
        }
      } catch (err) {
        console.error('Error during cleanup:', err);
      }
    }
  });
});

// Start server
const PORT = process.env.PORT || 3000;
httpServer.listen(PORT, () => {
  console.log(` Server running on http://localhost:${PORT}`);
  console.log(` WebSocket ready on ws://localhost:${PORT}`);
});
